# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

from decimal import Decimal, ROUND_HALF_UP


def _to_money(value):
    return Decimal(str(value)).quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


def process_transactions(accounts, transactions):
    """
    accounts: dict {account_id: balance}
    transactions: iterable of dicts
        Deposit  -> {"type": "deposit",  "account": "A",       "amount": 100}
        Withdraw -> {"type": "withdraw", "account": "A",       "amount": 50}
        Transfer -> {"type": "transfer", "from": "A", "to": "B","amount": 30}
    """
    balances = {aid: _to_money(bal) for aid, bal in accounts.items()}

    for tx in transactions:
        ttype = tx.get("type")
        amount = _to_money(tx.get("amount", 0))

        if amount <= 0:
            raise ValueError("Amount must be positive")

        if ttype == "deposit":
            acc = tx["account"]
            balances[acc] = balances.get(acc, Decimal("0.00")) + amount

        elif ttype == "withdraw":
            acc = tx["account"]
            if balances.get(acc, Decimal("0.00")) < amount:
                raise ValueError(f"Insufficient funds in account '{acc}'")
            balances[acc] -= amount

        elif ttype == "transfer":
            src = tx["from"]
            dst = tx["to"]
            if balances.get(src, Decimal("0.00")) < amount:
                raise ValueError(f"Insufficient funds in account '{src}'")
            balances[src] -= amount
            balances[dst] = balances.get(dst, Decimal("0.00")) + amount

        else:
            raise ValueError(f"Unknown transaction type '{ttype}'")

    return balances